class Solution {
public:
    bool isValidSudoku(vector<int>& board) {
        for (int i = 0; i < 9; i++) {
            set<int> row, col; row.insert(0); col.insert(0);
            for (int j = 0; j < 9; j++) {
                int num = board[i * 9 + j];
                if (num != 0 && row.find(num) != row.end()) return false;
                row.insert(num);
                num = board[j * 9 + i];
                if (num != 0 && col.find(num) != col.end()) return false;
                col.insert(num);
            }
        }
        for (int i = 0; i < 9; i += 3) {
            for (int j = 0; j < 9; j += 3) {
                set<int> box;
                box.insert(0);
                for (int k = 0; k < 3; k++) {
                    for (int l = 0; l < 3; l++) {
                        int num = board[i * 9 + j + k * 9 + l];
                        if (num != 0 && box.find(num) != box.end()) return false;
                        box.insert(num);
                    }
                }
            }
        }
        return true;
    }
};
